// BTCChart.jsx
import React, { useEffect, useState } from "react";
import { Line } from "react-chartjs-2";
import Chart from "chart.js/auto";

const BTCChart = () => {
  const [chartData, setChartData] = useState(null);
  const [error, setError] = useState(null);

  // Fetch BTC price history
  const fetchData = async () => {
    try {
      const res = await fetch("http://127.0.0.1:8000/markets");
      const data = await res.json();

      // Filter BTC and sort by timestamp
      const btcData = data
        .filter((d) => d.symbol === "BTC")
        .sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));

      if (btcData.length < 2) {
        setError(
          "Not enough data for chart (run /fetch multiple times)"
        );
        return;
      }

      // Map to chart format
      const formatted = {
        labels: btcData.map((d) => new Date(d.timestamp).toLocaleTimeString()),
        datasets: [
          {
            label: "BTC Price",
            data: btcData.map((d) => d.price),
            fill: false,
            backgroundColor: "rgba(255, 99, 132, 0.5)",
            borderColor: "rgba(255, 99, 132, 1)",
            tension: 0.2,
          },
        ],
      };

      setChartData(formatted);
      setError(null);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch chart data");
    }
  };

  useEffect(() => {
    fetchData();

    // Optional: auto-refresh every 30 seconds
    const interval = setInterval(fetchData, 30000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{ width: "100%", maxWidth: 800, margin: "0 auto" }}>
      <h2>BTC Price Chart</h2>
      {error && <p style={{ color: "red" }}>{error}</p>}
      {chartData ? (
        <Line data={chartData} />
      ) : !error ? (
        <p>Loading...</p>
      ) : null}
    </div>
  );
};

export default BTCChart;
